import api from './axios';

export const busApi = {
  // Search buses based on criteria (using new booking workflow API)
  searchBuses: async (searchCriteria) => {
    const response = await api.post('/booking-workflow/search-buses', searchCriteria);
    return response.data;
  },

  // Get bus details by ID
  getBusDetails: async (busId, travelDate) => {
    const response = await api.get(`/booking-workflow/bus-details/${busId}`, {
      params: { travelDate }
    });
    return response.data;
  },

  // Get seat layout for a specific bus
  getSeatLayout: async (busId, travelDate) => {
    const response = await api.get(`/booking-workflow/seat-availability/${busId}`, {
      params: { travelDate }
    });
    return response.data;
  },

  // Hold seats temporarily (prevent double booking)
  holdSeats: async (holdRequest) => {
    const response = await api.post('/booking-workflow/hold-seats', holdRequest);
    return response.data;
  },

  // Release held seats
  releaseSeats: async (releaseRequest) => {
    const response = await api.post('/booking-workflow/release-seats', releaseRequest);
    return response.data;
  },

  // Create booking (using new workflow)
  createBooking: async (bookingData) => {
    const response = await api.post('/booking-workflow/initiate-booking', bookingData);
    return response.data;
  },

  // Get user bookings
  getUserBookings: async () => {
    const response = await api.get('/bookings/my-bookings');
    return response.data;
  },

  // Get booking details
  getBookingDetails: async (bookingId) => {
    const response = await api.get(`/bookings/${bookingId}`);
    return response.data;
  },

  // Cancel booking
  cancelBooking: async (bookingId) => {
    const response = await api.delete(`/bookings/${bookingId}`);
    return response.data;
  },

  // Update seat availability after booking/cancellation
  updateSeatAvailability: async (busId, date, seatUpdates) => {
    const response = await api.put(`/buses/${busId}/seats/update`, {
      date,
      seatUpdates,
    });
    return response.data;
  },

  // Get all buses (for admin/manager)
  getAllBuses: async () => {
    const response = await api.get('/buses');
    return response.data;
  },

  // Create new bus (for admin/manager)
  createBus: async (busData) => {
    const response = await api.post('/buses', busData);
    return response.data;
  },

  // Update bus (for admin/manager)
  updateBus: async (busId, busData) => {
    const response = await api.put(`/buses/${busId}`, busData);
    return response.data;
  },

  // Delete bus (for admin)
  deleteBus: async (busId) => {
    const response = await api.delete(`/buses/${busId}`);
    return response.data;
  },

  // Get bus analytics (for admin/manager)
  getBusAnalytics: async () => {
    const response = await api.get('/buses/analytics');
    return response.data;
  },

  // Get booking analytics (for admin)
  getBookingAnalytics: async () => {
    const response = await api.get('/bookings/analytics');
    return response.data;
  },

  // Get all users (for admin)
  getAllUsers: async () => {
    const response = await api.get('/admin/users');
    return response.data;
  },

  // Update user role (for admin)
  updateUserRole: async (userId, role) => {
    const response = await api.put(`/admin/users/${userId}/role`, { role });
    return response.data;
  },
};
